"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[7445],{616:(s,n,a)=>{a.r(n),a.d(n,{data:()=>t});const t={key:"v-4182681c",path:"/knowledge/node/NodeJs%E4%B9%8BOS.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"os",slug:"os",children:[]},{level:2,title:"api",slug:"api",children:[]},{level:2,title:"与操作系统",slug:"与操作系统",children:[{level:3,title:"识别操作系统平台",slug:"识别操作系统平台",children:[]},{level:3,title:"理解和计算“平均负载”",slug:"理解和计算-平均负载",children:[]},{level:3,title:"理解和计算“cpu 使用率”",slug:"理解和计算-cpu-使用率",children:[]},{level:3,title:"理解和计算“内存使用率”",slug:"理解和计算-内存使用率",children:[]},{level:3,title:"查看运行时间",slug:"查看运行时间",children:[]}]}],filePathRelative:"knowledge/node/NodeJs之OS.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},2170:(s,n,a)=>{a.r(n),a.d(n,{default:()=>o});const t=(0,a(6252).uE)('<h2 id="os" tabindex="-1"><a class="header-anchor" href="#os" aria-hidden="true">#</a> os</h2><p>Node.js提供了一些基本的底层操作系统的模块OS.</p><h2 id="api" tabindex="-1"><a class="header-anchor" href="#api" aria-hidden="true">#</a> api</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">var</span> os <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;os&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[arch] 操作系统CPU架构&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">arch</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[cpus] 每个CPU/内核的信息:&#39;</span><span class="token operator">+</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>os<span class="token punctuation">.</span><span class="token function">cpus</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[endianness] CPU 的字节序:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">endianness</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[freemem] 操作系统空闲内存量:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">freemem</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[homedir] 当前用户使用的文件夹:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">homedir</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[hostname] 操作系统的主机名:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">hostname</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[loadavg] 平均负载:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">loadavg</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[networkInterfaces] 网络接口:&#39;</span><span class="token operator">+</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>os<span class="token punctuation">.</span><span class="token function">networkInterfaces</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[platform] 操作系统名:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">platform</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[release] 操作系统的发行版本:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">release</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[tmpdir] 操作系统的默认临时文件夹:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">tmpdir</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[totalmem] 系统内存总量:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">totalmem</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[type] 操作系统名:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">type</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;[uptime] 操作系统运行的时间:&#39;</span><span class="token operator">+</span>os<span class="token punctuation">.</span><span class="token function">uptime</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token punctuation">[</span>arch<span class="token punctuation">]</span> 操作系统CPU架构x64\n<span class="token punctuation">[</span>cpus<span class="token punctuation">]</span> 每个CPU/内核的信息:<span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token string">&quot;model&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;Intel(R) Core(TM) i5-4200H CPU @ 2.80GHz&quot;</span>,<span class="token string">&quot;speed&quot;</span>:2794,<span class="token string">&quot;times&quot;</span>:<span class="token punctuation">{</span><span class="token string">&quot;user&quot;</span>:12349500,<span class="token string">&quot;nice&quot;</span>:0,<span class="token string">&quot;sys&quot;</span>:13773515,<span class="token string">&quot;idle&quot;</span>:76721437,<span class="token string">&quot;irq&quot;</span>:1744218<span class="token punctuation">}</span><span class="token punctuation">}</span>,<span class="token punctuation">{</span><span class="token string">&quot;model&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;Intel(R) Core(TM) i5-4200H CPU @ 2.80GHz&quot;</span>,<span class="token string">&quot;speed&quot;</span>:2794,<span class="token string">&quot;times&quot;</span>:<span class="token punctuation">{</span><span class="token string">&quot;user&quot;</span>:12447781,<span class="token string">&quot;nice&quot;</span>:0,<span class="token string">&quot;sys&quot;</span>:11801625,<span class="token string">&quot;idle&quot;</span>:78594843,<span class="token string">&quot;irq&quot;</span>:320156<span class="token punctuation">}</span><span class="token punctuation">}</span>,<span class="token punctuation">{</span><span class="token string">&quot;model&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;Intel(R) Core(TM) i5-4200H CPU @ 2.80GHz&quot;</span>,<span class="token string">&quot;speed&quot;</span>:2794,<span class="token string">&quot;times&quot;</span>:<span class="token punctuation">{</span><span class="token string">&quot;user&quot;</span>:13889359,<span class="token string">&quot;nice&quot;</span>:0,<span class="token string">&quot;sys&quot;</span>:12343843,<span class="token string">&quot;idle&quot;</span>:76611046,<span class="token string">&quot;irq&quot;</span>:141578<span class="token punctuation">}</span><span class="token punctuation">}</span>,<span class="token punctuation">{</span><span class="token string">&quot;model&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;Intel(R) Core(TM) i5-4200H CPU @ 2.80GHz&quot;</span>,<span class="token string">&quot;speed&quot;</span>:2794,<span class="token string">&quot;times&quot;</span>:<span class="token punctuation">{</span><span class="token string">&quot;user&quot;</span>:12556328,<span class="token string">&quot;nice&quot;</span>:0,<span class="token string">&quot;sys&quot;</span>:11338265,<span class="token string">&quot;idle&quot;</span>:78949640,<span class="token string">&quot;irq&quot;</span>:128375<span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">]</span>\n<span class="token punctuation">[</span>endianness<span class="token punctuation">]</span> CPU 的字节序:LE\n<span class="token punctuation">[</span>freemem<span class="token punctuation">]</span> 操作系统空闲内存量:2904788992\n<span class="token punctuation">[</span>homedir<span class="token punctuation">]</span> 当前用户使用的文件夹:C:<span class="token punctuation">\\</span>Users<span class="token punctuation">\\</span>Administrator\n<span class="token punctuation">[</span>hostname<span class="token punctuation">]</span> 操作系统的主机名:SKYUSER-9PEIINO\n<span class="token punctuation">[</span>loadavg<span class="token punctuation">]</span> 平均负载:0,0,0\n<span class="token punctuation">[</span>networkInterfaces<span class="token punctuation">]</span> 网络接口:<span class="token punctuation">{</span><span class="token string">&quot;VMware Network Adapter VMnet1&quot;</span>:<span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token string">&quot;address&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;xxxxxxxxxxx&quot;</span>,<span class="token string">&quot;netmask&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;ffff:ffff:ffff:ffff::&quot;</span>,<span class="token string">&quot;family&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;IPv6&quot;</span>,<span class="token string">&quot;mac&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;00:50:56:c0:00:01&quot;</span>,<span class="token string">&quot;scopeid&quot;</span>:21,<span class="token string">&quot;internal&quot;</span>:false<span class="token punctuation">}</span>,<span class="token punctuation">{</span><span class="token string">&quot;address&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;192.168.80.1&quot;</span>,<span class="token string">&quot;netmask&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;255.255.255.0&quot;</span>,<span class="token string">&quot;family&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;IPv4&quot;</span>,<span class="token string">&quot;mac&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;00:50:56:c0:00:01&quot;</span>,<span class="token string">&quot;internal&quot;</span>:false<span class="token punctuation">}</span><span class="token punctuation">]</span>,<span class="token string">&quot;VMware Network Adapter VMnet8&quot;</span><span class="token builtin class-name">:</span>\n<span class="token punctuation">..</span><span class="token punctuation">..</span><span class="token punctuation">..</span>.,<span class="token string">&quot;scopeid&quot;</span>:0,<span class="token string">&quot;internal&quot;</span>:false<span class="token punctuation">}</span>,<span class="token punctuation">{</span><span class="token string">&quot;address&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;fe80::8cd:96a1:2214:bcfb&quot;</span>,<span class="token string">&quot;netmask&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;ffff:ffff:ffff:ffff::&quot;</span>,<span class="token string">&quot;family&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;IPv6&quot;</span>,<span class="token string">&quot;mac&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;00:00:00:00:00:00&quot;</span>,<span class="token string">&quot;scopeid&quot;</span>:8,<span class="token string">&quot;internal&quot;</span>:false<span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">}</span>\n<span class="token punctuation">[</span>platform<span class="token punctuation">]</span> 操作系统名:win32\n<span class="token punctuation">[</span>release<span class="token punctuation">]</span> 操作系统的发行版本:10.0.10240\n<span class="token punctuation">[</span>tmpdir<span class="token punctuation">]</span> 操作系统的默认临时文件夹:C:<span class="token punctuation">\\</span>Users<span class="token punctuation">\\</span>ADMINI~1<span class="token punctuation">\\</span>AppData<span class="token punctuation">\\</span>Local<span class="token punctuation">\\</span>Temp\n<span class="token punctuation">[</span>totalmem<span class="token punctuation">]</span> 系统内存总量:8473526272\n<span class="token punctuation">[</span>type<span class="token punctuation">]</span> 操作系统名:Windows_NT\n<span class="token punctuation">[</span>uptime<span class="token punctuation">]</span> 操作系统运行的时间:501123.2912315\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="与操作系统" tabindex="-1"><a class="header-anchor" href="#与操作系统" aria-hidden="true">#</a> 与操作系统</h2><p>读了 os 模块的文档，研究了几个有意思的问题：</p><ul><li>识别操作系统平台</li><li>理解和计算“平均负载”</li><li>理解和计算“cpu 使用率”</li><li>理解和计算“内存使用率”</li><li>查看运行时间</li></ul><h3 id="识别操作系统平台" tabindex="-1"><a class="header-anchor" href="#识别操作系统平台" aria-hidden="true">#</a> 识别操作系统平台</h3><p>nodejs 提供了os.platform()和os.type()，可以用来识别操作系统平台。推荐使用: os.platform()</p><h3 id="理解和计算-平均负载" tabindex="-1"><a class="header-anchor" href="#理解和计算-平均负载" aria-hidden="true">#</a> 理解和计算“平均负载”</h3><p>平均负载是指：单位时间内，系统处于可运行状态和不可中断状态的平均进程数。它和 cpu 使用率没有直接关系。</p><p>其中，这里的可运行状态指的是：正在使用 cpu 或正在等待 cpu 的进程。不可中断状态指的是：内核态关键流程中的进程。</p><p>在 nodejs 中，直接调用os.loadavg()可以获得 1、5 和 15 分钟的平均负载，它和 unix 命令uptime返回值一样。</p><p>为什么需要关心平均负载这个问题呢？因为进程分为 2 种，第一种就是“CPU 密集型”，它的 cpu 使用率和平均负载都是高的；第二种是“IO 密集型”，它的 cpu 使用率不一定高，但是等待 IO 会造成平均负载高。所以，cpu 使用率和平均负载共同反应系统性能。</p><p>平均活跃进程数最理想的状态是 cpu 数量=平均负载，如果 cpu 数量 &lt; 平均负载，那么平均负载过高。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>// 判断是否平均负载过高\n<span class="token keyword">function</span> <span class="token function-name function">isHighLoad</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\nconst cpuNum <span class="token operator">=</span> os.cpus<span class="token punctuation">(</span><span class="token punctuation">)</span>.length<span class="token punctuation">;</span>\n<span class="token builtin class-name">return</span> os.loadavg<span class="token punctuation">(</span><span class="token punctuation">)</span>.map<span class="token punctuation">(</span>item <span class="token operator">=</span><span class="token operator">&gt;</span> item <span class="token operator">&gt;</span> cpuNum<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="理解和计算-cpu-使用率" tabindex="-1"><a class="header-anchor" href="#理解和计算-cpu-使用率" aria-hidden="true">#</a> 理解和计算“cpu 使用率”</h3><p>很多监控软件都提供针对 cpu 使用率的“实时”监控，当然这个实时不是真的实时，有个时间差。这个功能，nodejs 如何实现呢？</p><p>第一步：封装getCPUInfo()，计算获取 cpu 花费的总时间与空闲模式花费的时间。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>/**\n* 获取cpu花费的总时间与空闲模式的时间\n  */\n  <span class="token keyword">function</span> <span class="token function-name function">getCPUInfo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  const cpus <span class="token operator">=</span> os.cpus<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token builtin class-name">let</span> user <span class="token operator">=</span> <span class="token number">0</span>,\n      <span class="token function">nice</span> <span class="token operator">=</span> <span class="token number">0</span>,\n      sys <span class="token operator">=</span> <span class="token number">0</span>,\n      idle <span class="token operator">=</span> <span class="token number">0</span>,\n      irq <span class="token operator">=</span> <span class="token number">0</span>,\n      total <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>  cpus.forEach<span class="token punctuation">(</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-function&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-params&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span>cpu<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token operator">=</span><span class="token operator">&amp;</span>gt<span class="token punctuation">;</span><span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token punctuation">{</span>\n    <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>const<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token punctuation">{</span> <span class="token builtin class-name">times</span> <span class="token punctuation">}</span> <span class="token operator">=</span> cpu<span class="token punctuation">;</span>\n    user <span class="token operator">+=</span> times.user<span class="token punctuation">;</span>\n    <span class="token function">nice</span> <span class="token operator">+=</span> times.nice<span class="token punctuation">;</span>\n    sys <span class="token operator">+=</span> times.sys<span class="token punctuation">;</span>\n    idle <span class="token operator">+=</span> times.idle<span class="token punctuation">;</span>\n    irq <span class="token operator">+=</span> times.irq<span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\ntotal <span class="token operator">=</span> user + <span class="token function">nice</span> + sys + idle + irq<span class="token punctuation">;</span>\n<span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>return<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token punctuation">{</span>\n    total,\n    idle\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>第二步：当前时间点 t1，选定一个时间差 intervel，计算 t1 和 t1 + interval 这两个时间点的 cpu 时间差与空闲模式时间差，返回 1 - 空闲时间差 / cpu时间差。返回的结果就是时间差 intervel 内的平均 cpu 使用率。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token keyword">function</span> getCPUUsage<span class="token punctuation">(</span>interval <span class="token operator">=</span> <span class="token number">1000</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    const startInfo <span class="token operator">=</span> getCPUInfo<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>return<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>new<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-built_in&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #0086b3; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>Promise<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-function&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-params&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span>resolve<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token operator">=</span><span class="token operator">&amp;</span>gt<span class="token punctuation">;</span><span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token punctuation">{</span>\n    setTimeout<span class="token punctuation">(</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-function&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-params&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;line-height: 26px;&quot;</span><span class="token operator">&gt;</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token operator">=</span><span class="token operator">&amp;</span>gt<span class="token punctuation">;</span><span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> <span class="token punctuation">{</span>\n        <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>const<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> endInfo <span class="token operator">=</span> getCPUInfo<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n        <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>const<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> idleDiff <span class="token operator">=</span> startInfo.idle - endInfo.idle<span class="token punctuation">;</span>\n        <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-keyword&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #333; font-weight: bold; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>const<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span> totalDiff <span class="token operator">=</span> startInfo.total - endInfo.total<span class="token punctuation">;</span>\n        resolve<span class="token punctuation">(</span><span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-number&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #008080; line-height: 26px;&quot;</span><span class="token operator">&gt;</span><span class="token operator"><span class="token file-descriptor important">1</span>&lt;</span>/span<span class="token operator">&gt;</span> - <span class="token operator">&lt;</span>span <span class="token assign-left variable">class</span><span class="token operator">=</span><span class="token string">&quot;hljs-built_in&quot;</span> <span class="token assign-left variable">style</span><span class="token operator">=</span><span class="token string">&quot;color: #0086b3; line-height: 26px;&quot;</span><span class="token operator">&gt;</span>Math<span class="token operator">&lt;</span>/span<span class="token operator">&gt;</span>.abs<span class="token punctuation">(</span>idleDiff / totalDiff<span class="token punctuation">))</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>, interval<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>使用方式如下：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>getCPUUsage<span class="token punctuation">(</span><span class="token punctuation">)</span>.then<span class="token punctuation">(</span>usage <span class="token operator">=</span><span class="token operator">&gt;</span> console.log<span class="token punctuation">(</span><span class="token string">&quot;cpu使用率：&quot;</span>, usage<span class="token punctuation">))</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="理解和计算-内存使用率" tabindex="-1"><a class="header-anchor" href="#理解和计算-内存使用率" aria-hidden="true">#</a> 理解和计算“内存使用率”</h3><p>cpu 的指标有平均负载、cpu 使用率，内存的指标有内存使用率。</p><p>借助 nodejs 接口，实现非常简单：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token keyword">function</span> <span class="token function-name function">getMemUsage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n<span class="token builtin class-name">return</span> <span class="token number">1</span> - os.freemem<span class="token punctuation">(</span><span class="token punctuation">)</span> / os.totalmem<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="查看运行时间" tabindex="-1"><a class="header-anchor" href="#查看运行时间" aria-hidden="true">#</a> 查看运行时间</h3><ul><li>nodejs 运行时间：process.uptime()</li><li>系统运行时间：os.uptime()</li></ul>',33),p={},o=(0,a(3744).Z)(p,[["render",function(s,n){return t}]])},3744:(s,n)=>{n.Z=(s,n)=>{const a=s.__vccOpts||s;for(const[s,t]of n)a[s]=t;return a}}}]);